package org.eclipse.rdf4j.query.explanation;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import org.junit.jupiter.api.Test;

class GenericPlanNodeTest {

	@Test
	void includesDecisionDiagnosticsInHumanReadableOutput() {
		GenericPlanNode node = new GenericPlanNode("Join");
		node.setDecisionDiagnostics("optimizer=cost-based; reordered=true");

		assertEquals("optimizer=cost-based; reordered=true", node.getDecisionDiagnostics());
		assertTrue(node.toString().contains("decisionDiagnostics=optimizer=cost-based; reordered=true"));
	}

	@Test
	void blankDecisionDiagnosticsAreTreatedAsUnset() {
		GenericPlanNode node = new GenericPlanNode("Join");
		node.setDecisionDiagnostics("   ");

		assertNull(node.getDecisionDiagnostics());
	}
}
